class Solution:
    def minPathSum(self, grid):
        m, n = len(grid), len(grid[0])
        INF = float('inf')
        dp = [[INF] * n for _ in range(m)]
        dp[0][0] = grid[0][0]
        for i in range(m):
            for j in range(n):
                if i == 0 and j == 0:
                    continue
                best = INF
                if i > 0:
                    best = min(best, dp[i - 1][j])
                if j > 0:
                    best = min(best, dp[i][j - 1])
                dp[i][j] = best + grid[i][j]
        return dp[m - 1][n - 1]

